insert into public.plant_catalog (
  id,
  slug,
  name_ru,
  name_latin,
  category,
  description,
  watering_interval_min,
  watering_interval_max,
  light_level,
  humidity_level,
  temperature_min,
  temperature_max,
  care_tips,
  risk_notes,
  soil_type,
  fertilizing_info,
  spraying_needed,
  pet_safe,
  difficulty_level,
  inspection_interval_days,
  spraying_interval_days,
  fertilizing_interval_days
)
values
  ('ficus-benjamina', 'ficus-benjamina', 'Фикус Бенджамина', 'Ficus benjamina', 'декоративно-лиственное', 'Популярное комнатное дерево с тонкими гибкими ветвями и мелкой листвой.', 7, 10, 'яркий рассеянный свет', 'средняя', 18, 26, 'Поливайте после подсыхания верхнего слоя грунта и избегайте резких перестановок.', 'Часто сбрасывает листья из-за сквозняков, перелива и стресса от смены места.', 'рыхлый универсальный грунт с дренажем', 'Подкормка для лиственных культур примерно раз в 30 дней в период активного роста.', false, false, 'средний', 14, null, 30),
  ('ficus-elastica', 'ficus-elastica', 'Фикус каучуконосный', 'Ficus elastica', 'декоративно-лиственное', 'Крупнолистный фикус с плотными кожистыми листьями.', 8, 12, 'яркий рассеянный свет', 'средняя', 18, 27, 'Нуждается в стабильном тепле, умеренном поливе и протирании листьев от пыли.', 'Плохо переносит холодные сквозняки и застой воды у корней.', 'питательный рыхлый грунт', 'Подкармливайте в теплый сезон раз в 30 дней.', false, false, 'средний', 14, null, 30),
  ('monstera-deliciosa', 'monstera-deliciosa', 'Монстера', 'Monstera deliciosa', 'декоративно-лиственное', 'Крупное тропическое растение с эффектными рассеченными листьями.', 6, 9, 'яркий рассеянный свет', 'высокая', 20, 28, 'Поддерживайте умеренную влажность грунта, добавляйте опору и берегите от палящего солнца.', 'Риск ожогов на листьях, вытягивания при недостатке света и загнивания корней при переливе.', 'воздухопроницаемый грунт с корой и перлитом', 'Подкармливайте раз в 30 дней в период роста.', true, false, 'средний', 14, 5, 30),
  ('spathiphyllum-wallisii', 'spathiphyllum-wallisii', 'Спатифиллум', 'Spathiphyllum wallisii', 'цветущее', 'Теневыносливое растение с блестящими листьями и белыми покрывалами цветков.', 4, 6, 'полутень', 'высокая', 19, 26, 'Любит равномерно влажный грунт, теплый воздух и мягкую воду.', 'Часто вянет от пересушки и желтеет при постоянном переливе.', 'легкий влагоемкий грунт', 'Подкормка для цветущих культур раз в 21-30 дней в сезон.', true, false, 'средний', 10, 3, 24),
  ('sansevieria-trifasciata', 'sansevieria-trifasciata', 'Сансевиерия', 'Sansevieria trifasciata', 'суккулент', 'Очень выносливое растение с плотными вертикальными листьями.', 12, 18, 'полутень', 'низкая', 18, 28, 'Поливайте редко и обязательно давайте грунту хорошо просохнуть между поливами.', 'Главный риск связан с переливом и холодной сыростью.', 'легкий грунт для суккулентов', 'Подкормка слабым раствором не чаще раза в 45 дней в сезон.', false, false, 'легкий', 21, null, 45),
  ('aloe-vera', 'aloe-vera', 'Алоэ', 'Aloe vera', 'суккулент', 'Суккулент с мясистыми листьями, который предпочитает много света и редкий полив.', 12, 18, 'яркий рассеянный свет', 'низкая', 18, 28, 'Держите на светлом месте и поливайте только после хорошего просыхания грунта.', 'Чаще всего страдает от перелива и недостатка света.', 'грунт для суккулентов с песком', 'Подкармливайте умеренно не чаще раза в 45 дней в теплый сезон.', false, false, 'легкий', 21, null, 45),
  ('zamioculcas-zamiifolia', 'zamioculcas-zamiifolia', 'Замиокулькас', 'Zamioculcas zamiifolia', 'декоративно-лиственное', 'Неприхотливое растение с плотными глянцевыми листьями.', 10, 16, 'полутень', 'низкая', 18, 28, 'Поливайте умеренно, избегая сырости в горшке и тяжелого грунта.', 'Переувлажнение вызывает пожелтение и потерю плотности побегов.', 'легкий грунт с хорошим дренажем', 'Подкормка для декоративно-лиственных растений раз в 30-45 дней.', false, false, 'легкий', 21, null, 40),
  ('phalaenopsis-orchid', 'phalaenopsis-orchid', 'Орхидея фаленопсис', 'Phalaenopsis orchid', 'цветущее', 'Эпифитная орхидея с продолжительным цветением и воздушными корнями.', 7, 10, 'яркий рассеянный свет', 'средняя', 19, 27, 'Поливайте после подсыхания коры, следите за корнями и не оставляйте воду в розетке.', 'Риск гнили корней при частом поливе и плохой вентиляции.', 'кора для орхидей с мхом и углем', 'Подкармливайте специальным удобрением для орхидей раз в 21-30 дней в период роста.', false, true, 'средний', 10, null, 24),
  ('dracaena-marginata', 'dracaena-marginata', 'Драцена маргината', 'Dracaena marginata', 'декоративно-лиственное', 'Изящная драцена с узкими длинными листьями и древовидным стволиком.', 6, 9, 'яркий рассеянный свет', 'средняя', 18, 27, 'Поддерживайте умеренный полив и избегайте жесткой воды.', 'Сухие кончики часто появляются из-за сухого воздуха и солей в воде.', 'универсальный рыхлый грунт', 'Подкармливайте раз в 30 дней в сезон.', false, false, 'легкий', 14, null, 30),
  ('chlorophytum-comosum', 'chlorophytum-comosum', 'Хлорофитум', 'Chlorophytum comosum', 'декоративно-лиственное', 'Выносливое растение с длинными дугообразными листьями и детками.', 5, 7, 'яркий рассеянный свет', 'средняя', 18, 26, 'Любит яркий рассеянный свет и регулярный, но не избыточный полив.', 'Сухие кончики появляются при сухом воздухе и избытке солей.', 'легкий универсальный грунт', 'Подкармливайте раз в 30 дней в активный сезон.', false, true, 'легкий', 14, null, 30),
  ('anthurium-andraeanum', 'anthurium-andraeanum', 'Антуриум', 'Anthurium andraeanum', 'цветущее', 'Тропическое растение с плотными листьями и яркими покрывалами соцветий.', 4, 6, 'яркий рассеянный свет', 'высокая', 20, 27, 'Держите в тепле, не пересушивайте полностью и поддерживайте высокую влажность воздуха.', 'Низкая влажность и холод быстро отражаются на листьях и цветении.', 'рыхлый воздухопроницаемый субстрат с корой', 'Подкормка для цветущих культур раз в 21-30 дней.', true, false, 'сложный', 10, 3, 24),
  ('calathea-ornata', 'calathea-ornata', 'Калатея', 'Calathea ornata', 'декоративно-лиственное', 'Декоративное тропическое растение с узорчатыми листьями.', 4, 6, 'полутень', 'высокая', 20, 26, 'Используйте мягкую воду, избегайте сквозняков и сухого воздуха.', 'Сухие кончики и скручивание листьев часто связаны с низкой влажностью.', 'влагоемкий рыхлый грунт', 'Подкармливайте раз в 30 дней слабым раствором.', true, true, 'сложный', 10, 3, 30),
  ('dieffenbachia-seguine', 'dieffenbachia-seguine', 'Диффенбахия', 'Dieffenbachia seguine', 'декоративно-лиственное', 'Быстрорастущее растение с крупными пестрыми листьями.', 5, 7, 'яркий рассеянный свет', 'средняя', 20, 28, 'Поддерживайте легкую влажность грунта и берегите от прямого солнца.', 'Перелив, холод и сквозняки быстро ухудшают внешний вид листьев.', 'питательный рыхлый грунт', 'Подкормка раз в 21-30 дней в сезон.', true, false, 'средний', 14, 5, 24),
  ('crassula-ovata', 'crassula-ovata', 'Толстянка', 'Crassula ovata', 'суккулент', 'Популярное суккулентное растение с мясистыми овальными листьями.', 12, 18, 'прямой свет', 'низкая', 18, 28, 'Поливайте редко, особенно зимой, и держите на светлом месте.', 'Избыток влаги часто вызывает размягчение листьев и загнивание корней.', 'грунт для суккулентов', 'Подкормка слабым раствором не чаще раза в 45 дней.', false, false, 'легкий', 21, null, 45),
  ('peperomia-obtusifolia', 'peperomia-obtusifolia', 'Пеперомия', 'Peperomia obtusifolia', 'декоративно-лиственное', 'Компактное растение с мясистыми округлыми листьями.', 6, 9, 'яркий рассеянный свет', 'средняя', 18, 26, 'Поливайте умеренно и не используйте слишком большой горшок.', 'Перелив и холодный подоконник часто вредят корням.', 'легкий воздухопроницаемый грунт', 'Подкормка раз в 30-40 дней в сезон.', false, true, 'легкий', 14, null, 35),
  ('saintpaulia-ionantha', 'saintpaulia-ionantha', 'Фиалка', 'Saintpaulia ionantha', 'цветущее', 'Компактное цветущее растение для светлого подоконника без прямого солнца.', 4, 6, 'яркий рассеянный свет', 'средняя', 19, 25, 'Поливайте осторожно по краю горшка или через поддон и избегайте воды на листьях.', 'Переувлажнение и попадание воды в центр розетки могут вызвать проблемы.', 'легкий грунт для сенполий', 'Подкормка для цветущих культур раз в 21-30 дней.', false, true, 'средний', 10, null, 24),
  ('begonia-elatior', 'begonia-elatior', 'Бегония', 'Begonia elatior', 'цветущее', 'Цветущее растение с декоративной листвой и яркими соцветиями.', 4, 6, 'яркий рассеянный свет', 'средняя', 18, 24, 'Держите в умеренно влажном грунте и хорошей вентиляции без сквозняков.', 'Часто страдает от сырости, холодного воздуха и ожогов от прямого солнца.', 'легкий питательный грунт', 'Подкормка для цветущих растений раз в 21-30 дней.', false, false, 'средний', 10, null, 24),
  ('yucca-elephantipes', 'yucca-elephantipes', 'Юкка', 'Yucca elephantipes', 'декоративно-лиственное', 'Древовидное растение с плотными жесткими листьями и высокой устойчивостью.', 10, 14, 'яркий свет', 'низкая', 18, 28, 'Лучше чувствует себя на светлом месте и не любит частый полив.', 'Основной риск — переувлажнение и нехватка света.', 'рыхлый дренированный грунт', 'Подкормка раз в 30-45 дней в теплый сезон.', false, false, 'легкий', 21, null, 40),
  ('aglaonema-commutatum', 'aglaonema-commutatum', 'Аглаонема', 'Aglaonema commutatum', 'декоративно-лиственное', 'Теневыносливое растение с декоративными пестрыми листьями.', 5, 8, 'полутень', 'средняя', 20, 27, 'Избегайте переохлаждения и поддерживайте умеренный полив.', 'Сквозняки и холод часто вызывают потерю декоративности.', 'легкий питательный грунт', 'Подкормка раз в 30 дней в сезон.', false, false, 'средний', 14, null, 30),
  ('philodendron-hederaceum', 'philodendron-hederaceum', 'Филодендрон', 'Philodendron hederaceum', 'лиана', 'Вьющееся растение с сердцевидными листьями, хорошо растет в комнатных условиях.', 5, 8, 'яркий рассеянный свет', 'средняя', 19, 27, 'Поливайте после подсыхания верхнего слоя и обеспечьте опору при активном росте.', 'Перелив и слишком темное место замедляют рост и ухудшают листья.', 'рыхлый грунт для ароидных', 'Подкормка раз в 21-30 дней в сезон.', true, false, 'легкий', 14, 5, 24),
  ('nephrolepis-exaltata', 'nephrolepis-exaltata', 'Нефролепис', 'Nephrolepis exaltata', 'папоротник', 'Популярный комнатный папоротник с ажурной пышной листвой.', 3, 5, 'полутень', 'высокая', 18, 24, 'Не допускайте полного пересыхания кома и поддерживайте повышенную влажность воздуха.', 'Сухой воздух быстро вызывает подсыхание вай и потерю декоративности.', 'рыхлый влагоемкий грунт', 'Подкормка слабым раствором раз в 30 дней в теплый сезон.', true, true, 'средний', 10, 3, 30),
  ('hedera-helix', 'hedera-helix', 'Плющ', 'Hedera helix', 'лиана', 'Компактная или свисающая лиана для прохладных светлых помещений.', 4, 6, 'яркий рассеянный свет', 'средняя', 15, 23, 'Любит свежий воздух, умеренную влажность и прохладу без пересушивания.', 'Жара и сухой воздух часто вызывают осыпание листьев.', 'легкий рыхлый грунт', 'Подкормка раз в 21-30 дней в сезон.', true, false, 'средний', 10, 5, 24),
  ('schefflera-arboricola', 'schefflera-arboricola', 'Шеффлера', 'Schefflera arboricola', 'декоративно-лиственное', 'Декоративное растение с зонтичными листьями и быстрым ростом.', 6, 9, 'яркий рассеянный свет', 'средняя', 18, 26, 'Поливайте умеренно и поворачивайте растение к свету для ровной кроны.', 'Слишком тень и сырость приводят к вытягиванию и потере листьев.', 'универсальный грунт с дренажем', 'Подкормка раз в 30 дней в сезон.', false, false, 'легкий', 14, null, 30),
  ('pachira-aquatica', 'pachira-aquatica', 'Пахира', 'Pachira aquatica', 'декоративно-лиственное', 'Растение с плетеным стволом и пальчатыми листьями.', 7, 10, 'яркий рассеянный свет', 'средняя', 18, 27, 'Поддерживайте умеренную влажность почвы и избегайте холодных сквозняков.', 'Переувлажнение и холод часто вызывают потерю упругости и пятна на листьях.', 'легкий рыхлый грунт', 'Подкормка раз в 30 дней в сезон.', true, true, 'средний', 14, 7, 30),
  ('croton-variegatum', 'croton-variegatum', 'Кротон', 'Codiaeum variegatum', 'декоративно-лиственное', 'Яркое растение с пестрой листвой, требовательное к свету и влажности.', 4, 6, 'яркий рассеянный свет', 'высокая', 20, 27, 'Держите в тепле, на хорошем свету и без резких перестановок.', 'Плохо переносит сухой воздух, недостаток света и сквозняки.', 'питательный рыхлый грунт', 'Подкормка раз в 21-30 дней в сезон.', true, false, 'сложный', 10, 3, 24),
  ('epipremnum-aureum', 'epipremnum-aureum', 'Эпипремнум', 'Epipremnum aureum', 'лиана', 'Неприхотливая лиана с быстрым ростом и декоративными листьями.', 5, 8, 'полутень', 'средняя', 18, 27, 'Поливайте после подсыхания верхнего слоя и обеспечьте рассеянный свет для хорошего рисунка листа.', 'В глубокой тени листья мельчают и теряют окраску.', 'универсальный рыхлый грунт', 'Подкормка раз в 30 дней в сезон.', true, false, 'легкий', 14, 7, 30),
  ('scindapsus-pictus', 'scindapsus-pictus', 'Сциндапсус', 'Scindapsus pictus', 'лиана', 'Эффектная лиана с серебристыми пятнами на листьях.', 5, 8, 'яркий рассеянный свет', 'средняя', 18, 27, 'Любит стабильный полив и яркий рассеянный свет без ожогов.', 'Слишком сухой воздух и темное место снижают декоративность.', 'рыхлый грунт для лиан', 'Подкормка раз в 30 дней в сезон.', true, false, 'легкий', 14, 7, 30),
  ('chamedorea-elegans', 'chamedorea-elegans', 'Хамедорея', 'Chamaedorea elegans', 'пальма', 'Компактная комнатная пальма, хорошо подходящая для полутени.', 5, 7, 'полутень', 'средняя', 18, 26, 'Поддерживайте умеренную влажность грунта и не пересушивайте воздух надолго.', 'Сухой воздух и холодные сквозняки часто повреждают листья.', 'легкий влагоемкий грунт', 'Подкормка для пальм раз в 30 дней в сезон.', true, true, 'легкий', 14, 7, 30),
  ('cactus-mix', 'cactus-mix', 'Кактусы', 'Cactus mix', 'суккулент', 'Сборная категория для большинства домашних кактусов.', 14, 25, 'прямой свет', 'низкая', 18, 30, 'Поливайте редко, держите на максимально светлом месте и не заливайте зимой.', 'Наиболее частая проблема — перелив и загнивание основания.', 'минеральный грунт для кактусов', 'Подкормка слабым раствором не чаще раза в 45-60 дней в теплый сезон.', false, false, 'легкий', 21, null, 50),
  ('succulent-mix', 'succulent-mix', 'Суккуленты', 'Succulent mix', 'суккулент', 'Группа неприхотливых растений, предпочитающих свет и редкий полив.', 10, 18, 'яркий свет', 'низкая', 18, 28, 'Давайте грунту просохнуть между поливами и не используйте тяжелый субстрат.', 'Избыток воды и недостаток света быстро портят форму и окраску.', 'грунт для суккулентов', 'Подкормка умеренно раз в 45 дней в теплый сезон.', false, false, 'легкий', 21, null, 45),
  ('pilea-peperomioides', 'pilea-peperomioides', 'Пилея', 'Pilea peperomioides', 'декоративно-лиственное', 'Компактное растение с круглыми листьями на длинных черешках.', 5, 7, 'яркий рассеянный свет', 'средняя', 18, 25, 'Поливайте после подсыхания верхнего слоя и поворачивайте растение к свету.', 'Нехватка света и постоянная сырость вызывают вытягивание и потерю формы.', 'легкий рыхлый грунт', 'Подкормка раз в 30 дней в сезон.', false, true, 'легкий', 14, null, 30),
  ('syngonium-podophyllum', 'syngonium-podophyllum', 'Сингониум', 'Syngonium podophyllum', 'лиана', 'Быстрорастущее ароидное растение с изменяющейся формой листьев.', 5, 8, 'яркий рассеянный свет', 'средняя', 19, 27, 'Поддерживайте умеренный полив и время от времени обновляйте опору.', 'При сухом воздухе кончики листьев сохнут, а в темноте рост слабеет.', 'рыхлый грунт для ароидных', 'Подкормка раз в 21-30 дней в сезон.', true, false, 'легкий', 14, 5, 24),
  ('hoya-carnosa', 'hoya-carnosa', 'Хойя', 'Hoya carnosa', 'лиана', 'Лиана с плотными листьями и ароматными соцветиями при хорошем освещении.', 7, 10, 'яркий рассеянный свет', 'средняя', 18, 27, 'Не переливайте, не переставляйте часто во время бутонизации и обеспечьте хороший свет.', 'Частые перестановки и сырость могут мешать цветению.', 'легкий воздухопроницаемый грунт', 'Подкормка для цветущих растений раз в 30 дней в теплый сезон.', false, true, 'средний', 14, null, 30)
on conflict (id) do update
set
  slug = excluded.slug,
  name_ru = excluded.name_ru,
  name_latin = excluded.name_latin,
  category = excluded.category,
  description = excluded.description,
  watering_interval_min = excluded.watering_interval_min,
  watering_interval_max = excluded.watering_interval_max,
  light_level = excluded.light_level,
